'use strict';
/**
 * REGRESSION — FRG-234
 * Talk Handshaking
 *
 * Verifies the character-to-character conversation system:
 *  - Characters can initiate talk via AI action: 'talk'
 *  - On accept: both enter talking state, TALK event appears in event log
 *  - On reject: REJECT event appears in event log with reason
 *  - canTalk filter: LLM receives canTalk status for nearby characters
 *  - Talk targets observed across all characters over time
 *
 * Target: /debug.html (for event log) and / (for engine state)
 */
const { test, expect } = require('@playwright/test');
const { waitForEngine, pollEngineState, waitForDashboard } = require('../helpers');

test.describe('M1: Talk Handshaking', () => {
  // ── TALK EVENTS IN EVENT LOG ──────────────────────────────────────────────

  test('TALK event appears in event log within 90 seconds', async ({ page }) => {
    test.setTimeout(120_000);

    await page.goto('/debug.html');
    await waitForDashboard(page);

    // Enable 4x speed to accelerate AI cycles
    await page.getByRole('button', { name: '4x' }).click();

    await page.waitForFunction(
      () => document.querySelector('.log-entry.talk') !== null,
      { timeout: 90_000, polling: 1000 }
    );

    const talkEntries = await page.evaluate(() => {
      const entries = document.querySelectorAll('.log-entry.talk');
      return Array.from(entries).map(e => ({
        obj: e.querySelector('.log-obj')?.textContent.trim(),
        transition: e.querySelector('.log-transition')?.textContent.trim(),
        tag: e.querySelector('.log-tag')?.textContent.trim(),
      }));
    });

    expect(talkEntries.length).toBeGreaterThan(0);
    for (const entry of talkEntries) {
      expect(entry.tag).toBe('TALK');
      // Transition should show "talking ↔ CharacterName"
      expect(entry.transition).toMatch(/talking\s*↔\s*(Maple|Sol|Nyx)/);
      // obj should be a character name
      expect(['Maple', 'Sol', 'Nyx']).toContain(entry.obj);
    }
    console.log('TALK events found:', talkEntries);
  });

  test('AI decision with action=talk appears in event log', async ({ page }) => {
    test.setTimeout(120_000);

    await page.goto('/debug.html');
    await waitForDashboard(page);

    // Enable 4x speed
    await page.getByRole('button', { name: '4x' }).click();

    // Wait for an AI event with "talk →" transition
    await page.waitForFunction(
      () => {
        const entries = document.querySelectorAll('.log-entry.ai');
        return Array.from(entries).some(e => {
          const t = e.querySelector('.log-transition');
          return t && t.textContent.includes('talk →');
        });
      },
      { timeout: 90_000, polling: 1000 }
    );

    const talkAiEntries = await page.evaluate(() => {
      const entries = document.querySelectorAll('.log-entry.ai');
      return Array.from(entries)
        .filter(e => e.querySelector('.log-transition')?.textContent.includes('talk →'))
        .map(e => ({
          obj: e.querySelector('.log-obj')?.textContent.trim(),
          transition: e.querySelector('.log-transition')?.textContent.trim(),
        }));
    });

    expect(talkAiEntries.length).toBeGreaterThan(0);
    for (const entry of talkAiEntries) {
      expect(['Maple', 'Sol', 'Nyx']).toContain(entry.obj);
      expect(entry.transition).toMatch(/talk → (Maple|Sol|Nyx)/);
    }
    console.log('AI talk decisions:', talkAiEntries);
  });

  // ── REJECT EVENTS ──────────────────────────────────────────────────────────

  test('REJECT event appears in event log when character is busy', async ({ page }) => {
    test.setTimeout(180_000);

    await page.goto('/debug.html');
    await waitForDashboard(page);

    // Enable 4x speed to see more AI cycles
    await page.getByRole('button', { name: '4x' }).click();

    // REJECT events are probabilistic — they only fire when someone tries to talk
    // to a character who is interacting or already talking.
    // Wait up to 2.5 minutes (covers ~5 AI cycles at 30s each)
    const found = await page.waitForFunction(
      () => document.querySelector('.log-entry.reject') !== null,
      { timeout: 150_000, polling: 1000 }
    ).catch(() => null);

    if (!found) {
      // REJECT events only happen when characters happen to conflict.
      // Log a note but don't fail — this is probabilistic, not a product bug.
      console.log('[SKIP] No REJECT events observed in this run (probabilistic — requires talk attempt on busy character)');
      return;
    }

    const rejectEntries = await page.evaluate(() => {
      const entries = document.querySelectorAll('.log-entry.reject');
      return Array.from(entries).map(e => ({
        obj: e.querySelector('.log-obj')?.textContent.trim(),
        transition: e.querySelector('.log-transition')?.textContent.trim(),
        tag: e.querySelector('.log-tag')?.textContent.trim(),
      }));
    });

    expect(rejectEntries.length).toBeGreaterThan(0);
    for (const entry of rejectEntries) {
      expect(entry.tag).toBe('REJECT');
      // Transition shows "→ CharacterName rejected (reason)"
      expect(entry.transition).toMatch(/→\s*(Maple|Sol|Nyx)\s+rejected/);
    }
    console.log('REJECT events found:', rejectEntries);
  });

  // ── CAN-TALK FILTER ───────────────────────────────────────────────────────

  test('LLM request body includes canTalk status for nearby characters', async ({ page }) => {
    const requestBodies = [];

    page.on('request', req => {
      if (req.url().includes('/api/llm') && req.method() === 'POST') {
        try {
          requestBodies.push(JSON.parse(req.postData() || '{}'));
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 20_000 }
    );
    await page.waitForTimeout(10_000);

    // At least some requests should include character info with canTalk
    const withCanTalk = requestBodies.filter(body => {
      const content = body.messages?.[0]?.content || '';
      return content.includes('canTalk');
    });

    if (withCanTalk.length === 0) {
      // canTalk may be in the system prompt instead of the user message
      const withNearbyChars = requestBodies.filter(body => {
        const sys = body.system || '';
        const user = body.messages?.[0]?.content || '';
        return sys.includes('canTalk') || user.includes('Nearby characters') || user.includes('characters');
      });
      expect(withNearbyChars.length, 'LLM requests should include character availability info').toBeGreaterThan(0);
      console.log('Character info in LLM requests (system or user message):', withNearbyChars.length);
    } else {
      expect(withCanTalk.length).toBeGreaterThan(0);
      console.log('LLM requests with canTalk field:', withCanTalk.length);
    }
  });

  // ── CHARACTERS ENTER TALKING STATE ────────────────────────────────────────

  test('characters enter talking action state during conversation', async ({ page }) => {
    test.setTimeout(120_000);

    await page.goto('/');
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 20_000 }
    );

    // Poll engine state for any character in talking state
    const talkState = await pollEngineState(
      page,
      state => state.characters.some(c => c.action === 'talking'),
      90_000,
      500
    ).catch(() => null);

    if (!talkState) {
      console.log('[SKIP] No talking state observed in this run (AI may not have chosen talk action)');
      return;
    }

    const talkers = talkState.characters.filter(c => c.action === 'talking');
    expect(talkers.length).toBeGreaterThanOrEqual(1);
    console.log('Characters in talking state:', talkers.map(c => c.label).join(', '));
  });

  // ── TALK TARGETS DISTRIBUTED ACROSS CHARACTERS ───────────────────────────

  test('talk action targets distributed across multiple characters over time', async ({ page }) => {
    test.setTimeout(120_000);

    const talkTargets = new Set();

    page.on('response', async res => {
      if (res.url().includes('/api/llm') && res.request().method() === 'POST') {
        try {
          const json = await res.json();
          const text = json?.content?.[0]?.text ?? json?.choices?.[0]?.message?.content;
          if (text) {
            const d = JSON.parse(text);
            if (d.action === 'talk' && d.targetCharacter) {
              talkTargets.add(d.targetCharacter);
            }
          }
        } catch { /* ignore */ }
      }
    });

    await page.goto('/');
    await page.waitForFunction(
      () => window._gameEngine?.characters?.length === 3,
      { timeout: 20_000 }
    );
    await page.waitForTimeout(90_000);

    if (talkTargets.size === 0) {
      console.log('[INFO] No talk actions observed in this run — AI chose other actions');
      // Not a failure: AI is non-deterministic. The LLM responses valid action test already covers this.
      return;
    }

    // If talk actions were observed, targets should be valid character names
    for (const target of talkTargets) {
      expect(['Maple', 'Sol', 'Nyx']).toContain(target);
    }
    console.log('Talk targets observed:', [...talkTargets]);
  });
});

