// ═══════════════════════════════════════════════════════════
// AI Decision Engine — LLM-driven character decisions
// ═══════════════════════════════════════════════════════════
//
// Sits on top of the existing wander system. When enabled,
// characters make decisions via the AI API instead of wandering
// randomly. Falls back to random wander on failure/timeout.

import { AIClient } from './api.js';
import { findInteractTile } from './characters.js';
import { SECTORS } from './world.js';

const STAGGER_MS = 12000;
const COOLDOWN_MIN = 30000;
const COOLDOWN_MAX = 60000;

export class AIDecisionEngine {
  constructor(options = {}) {
    this.client = new AIClient({
      endpoint: options.endpoint || '',
      timeoutMs: options.timeoutMs || 15000,
    });
    this.engine = null;
    this.charState = new Map();
    this.pendingMessages = new Map(); // charId → [{ from, dialogue }]
  }

  /** Link to the simulation engine (called once during setup). */
  attach(engine) {
    this.engine = engine;
    this.charState.clear();
    this.pendingMessages.clear();
    engine.characters.forEach((char, i) => {
      this.charState.set(char.id, {
        cooldownMs: 5000 + i * STAGGER_MS,
        pending: false,
      });
    });
  }

  setEndpoint(url) {
    this.client.endpoint = url;
  }

  get endpoint() {
    return this.client.endpoint;
  }

  /** Returns true if this character has a pending AI decision. */
  isPending(charId) {
    return this.charState.get(charId)?.pending || false;
  }

  /** Called each engine tick for each idle character. */
  tick(char, deltaMs) {
    const state = this.charState.get(char.id);
    if (!state || state.pending) return;

    state.cooldownMs -= deltaMs;
    if (state.cooldownMs > 0) return;

    state.cooldownMs = COOLDOWN_MIN + Math.random() * (COOLDOWN_MAX - COOLDOWN_MIN);
    state.pending = true;

    this._requestDecision(char).catch(() => {});
  }

  async _requestDecision(char) {
    const state = this.charState.get(char.id);
    const engineRef = this.engine;

    try {
      if (!this.client.endpoint) {
        throw new Error('No API endpoint configured');
      }

      const objects = engineRef.objectEngine.getAll();
      const characters = engineRef.characters;
      const perception = char.getPerception(objects, characters);

